## File to create

### `apps/client/src/layers/features/status/__tests__/PermissionModeItem.test.tsx`

The test file needs the jsdom environment directive and standard testing imports:

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeAll } from 'vitest';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import '@testing-library/jest-dom';
import { PermissionModeItem } from '../ui/PermissionModeItem';

// Mock matchMedia for responsive components
beforeAll(() => {
  Object.defineProperty(window, 'matchMedia', {
    writable: true,
    value: vi.fn().mockImplementation((query) => ({
      matches: false,
      media: query,
      onchange: null,
      addListener: vi.fn(),
      removeListener: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
  });
});

describe('PermissionModeItem', () => {
  it('renders the current mode label', () => {
    render(<PermissionModeItem mode="default" onChangeMode={vi.fn()} />);
    expect(screen.getByText('Default')).toBeInTheDocument();
  });

  it('renders all 6 permission modes in the dropdown', async () => {
    const user = userEvent.setup();
    render(<PermissionModeItem mode="default" onChangeMode={vi.fn()} />);
    await user.click(screen.getByText('Default'));
    expect(screen.getByText('Default')).toBeInTheDocument();
    expect(screen.getByText('Accept Edits')).toBeInTheDocument();
    expect(screen.getByText('Plan Mode')).toBeInTheDocument();
    expect(screen.getByText("Don't Ask")).toBeInTheDocument();
    expect(screen.getByText('Bypass All')).toBeInTheDocument();
    expect(screen.getByText('Auto')).toBeInTheDocument();
  });

  it('filters modes by supportedModes prop', async () => {
    const user = userEvent.setup();
    render(
      <PermissionModeItem
        mode="default"
        onChangeMode={vi.fn()}
        supportedModes={['default', 'plan']}
      />,
    );
    await user.click(screen.getByText('Default'));
    expect(screen.getByText('Default')).toBeInTheDocument();
    expect(screen.getByText('Plan Mode')).toBeInTheDocument();
    expect(screen.queryByText('Bypass All')).not.toBeInTheDocument();
    expect(screen.queryByText('Auto')).not.toBeInTheDocument();
    expect(screen.queryByText("Don't Ask")).not.toBeInTheDocument();
  });

  it('shows the current mode in the trigger even if not in supportedModes', () => {
    render(
      <PermissionModeItem
        mode="auto"
        onChangeMode={vi.fn()}
        supportedModes={['default', 'plan']}
      />,
    );
    expect(screen.getByText('Auto')).toBeInTheDocument();
  });

  it('calls onChangeMode when a mode is selected', async () => {
    const onChangeMode = vi.fn();
    const user = userEvent.setup();
    render(<PermissionModeItem mode="default" onChangeMode={onChangeMode} />);
    await user.click(screen.getByText('Default'));
    await user.click(screen.getByText('Plan Mode'));
    expect(onChangeMode).toHaveBeenCalledWith('plan');
  });

  it('shows disabled tooltip when disabled', () => {
    render(<PermissionModeItem mode="default" onChangeMode={vi.fn()} disabled />);
    const trigger = screen.getByText('Default');
    expect(trigger.closest('button')).toBeDisabled();
  });

  it('renders dontAsk mode correctly in the trigger', () => {
    render(<PermissionModeItem mode="dontAsk" onChangeMode={vi.fn()} />);
    expect(screen.getByText("Don't Ask")).toBeInTheDocument();
  });

  it('renders auto mode correctly in the trigger', () => {
    render(<PermissionModeItem mode="auto" onChangeMode={vi.fn()} />);
    expect(screen.getByText('Auto')).toBeInTheDocument();
  });
});
```

Note: Testing the exact CSS class (`text-red-500`) on dropdown items may require querying the DOM more carefully depending on how `ResponsiveDropdownMenuRadioItem` renders. If direct class testing is fragile, focus on behavioral tests (mode selection, filtering, trigger label) which are more stable.

